static void tdr_switch_eb(lv_event_t * e ){
    lv_event_code_t code= lv_event_get_code(e);
    lv_obj_t * obj= lv_event_get_target(e);
    if(code==LV_EVENT_VALUE_CHANGED){
        if(lv_obj_has_state(obj,LV_STATE_CHECKED)){
            lv_chart_set_range(ui_Chart3,LV_CHART_AXIS_PRIMARY_Y,0,last_primary_axis_y_tdr);
            lv_chart_set_range(ui_Chart3,LV_CHART_AXIS_PRIMARY_X,last_primary_axis_x_tdr_l,last_primary_axis_x_tdr_h);
            lv_chart_hide_series(ui_Chart3,ui_Chart3_mag,1);
            lv_chart_hide_series(ui_Chart3,ui_Chart3_phase,1);
            lv_chart_hide_series(ui_Chart3,ui_Chart3_tdr,0);
        }else{
            lv_chart_set_range(ui_Chart3,LV_CHART_AXIS_PRIMARY_Y,0,last_primary_axis_y_spec);
            lv_chart_set_range(ui_Chart3,LV_CHART_AXIS_PRIMARY_X,last_primary_axis_x_spec_l,last_primary_axis_x_spec_h);
            lv_chart_hide_series(ui_Chart3,ui_Chart3_mag,0);
            lv_chart_hide_series(ui_Chart3,ui_Chart3_phase,0);
            lv_chart_hide_series(ui_Chart3,ui_Chart3_tdr,1);

        }
    }
}

